export const SubscribeBody = zod.object({
  "email": zod.string().min(subscribeBodyEmailMin).max(subscribeBodyEmailMax)
})

export const SubscribeResponse = zod.object({
  "ok": zod.boolean(),
  "status": zod.string()
})


/**
 * @summary List subscribers (admin)
 */
export const ListSubscribersResponse = zod.object({
  "total": zod.number(),
  "active": zod.number(),
  "subscribers": zod.array(zod.object({
  "id": zod.string(),
  "email": zod.string(),
  "status": zod.string(),
  "createdAt": zod.string(),
  "unsubscribedAt": zod.string().nullish()
}))
})


